def _default_local_assignment(lobby: Lobby) -> dict[str, str] | None:
    cfg = get_app_config()
    if not cfg.MAIN_APP_INCLUDE_GAME_WS:
        return None
    game_ws_base_url = _to_ws_base_url(cfg.GAME_WS_PUBLIC_BASE_URL or cfg.BACKEND_PUBLIC_BASE_URL)
    chat_ws_base_url = _to_ws_base_url(cfg.CHAT_WS_PUBLIC_BASE_URL or cfg.BACKEND_PUBLIC_BASE_URL)
    if not game_ws_base_url or not chat_ws_base_url:
        return None
    return _materialize_assignment(
