    return {
        "gameWsUrl": f"{game_ws_base.rstrip('/')}/api/v1/ws/game/{encoded_lobby_id}",
        "chatWsUrl": f"{chat_ws_base.rstrip('/')}/api/v1/ws/lobby/{encoded_lobby_id}",
    }

